+    // ============ MoE Engine Interface ============
+    pub const MoEEngine = model.MoEEngine;
+
+    /// Get MoEEngine interface for this MetalMoEEngine
+    pub fn asMoEEngine(self: *Self) MoEEngine {
+        return MoEEngine{
+            .ptr = self,
+            .vtable = &moe_vtable,
+        };
+    }
+
+    const moe_vtable = MoEEngine.VTable{
+        .encodeZeroBuffer = struct {
+            fn f(ptr: *anyopaque, cmd_buf: objc.MTLCommandBuffer, buf: objc.MTLBuffer, n: u32) anyerror!void {
+                const self_ptr: *Self = @ptrCast(@alignCast(ptr));
+                return self_ptr.encodeZeroBuffer(cmd_buf, buf, n);
+            }
+        }.f,
+        .encodeAdd = struct {
+            fn f(ptr: *anyopaque, cmd_buf: objc.MTLCommandBuffer, a: objc.MTLBuffer, b: objc.MTLBuffer, out: objc.MTLBuffer, n: u32) anyerror!void {
+                const self_ptr: *Self = @ptrCast(@alignCast(ptr));
+                return self_ptr.encodeAdd(cmd_buf, a, b, out, n);
+            }
+        }.f,
+        .encodeExpertFFN_Q2K_HybridFromSoftmax = struct {
+            fn f(
+                ptr: *anyopaque,
+                cmd_buf: objc.MTLCommandBuffer,
+                buf_normed: objc.MTLBuffer,
+                gate_buf: objc.MTLBuffer,
+                up_buf: objc.MTLBuffer,
+                down_buf: objc.MTLBuffer,
+                buf_output: objc.MTLBuffer,
+                buf_expert_weights: objc.MTLBuffer,
+                expert_idx: u32,
+                layer_idx: u32,
+                n_embd: u32,
+                n_ff: u32,
+            ) anyerror!void {
+                const self_ptr: *Self = @ptrCast(@alignCast(ptr));
+                return self_ptr.encodeExpertFFN_Q2K_HybridFromSoftmax(
+                    cmd_buf,
+                    buf_normed,
+                    gate_buf,
+                    up_buf,
+                    down_buf,
+                    buf_output,
+                    buf_expert_weights,
+                    expert_idx,
+                    layer_idx,
+                    n_embd,
+                    n_ff,
+                );
+            }
+        }.f,
+        .encodeExpertFFN_Q4_BufferFromSoftmax = struct {
+            fn f(
+                ptr: *anyopaque,
+                cmd_buf: objc.MTLCommandBuffer,
+                buf_normed: objc.MTLBuffer,
+                gate_buf: objc.MTLBuffer,
+                up_buf: objc.MTLBuffer,
+                down_buf: objc.MTLBuffer,
+                buf_output: objc.MTLBuffer,
+                buf_expert_weights: objc.MTLBuffer,
+                expert_idx: u32,
+                n_embd: u32,
+                n_ff: u32,
+            ) anyerror!void {
+                const self_ptr: *Self = @ptrCast(@alignCast(ptr));
+                return self_ptr.encodeExpertFFN_Q4_BufferFromSoftmax(
+                    cmd_buf,
+                    buf_normed,
+                    gate_buf,
+                    up_buf,
+                    down_buf,
+                    buf_output,
+                    buf_expert_weights,
+                    expert_idx,
+                    n_embd,
+                    n_ff,
+                );
+            }
+        }.f,
+        .getOrCreateHybridQ2KBuffer = struct {
+            fn f(ptr: *anyopaque, name: []const u8) anyerror!objc.MTLBuffer {
+                const self_ptr: *Self = @ptrCast(@alignCast(ptr));
+                return self_ptr.getOrCreateHybridQ2KBuffer(name);
+            }
+        }.f,
+        .getOrCreateTensorBuffer = struct {
+            fn f(ptr: *anyopaque, name: []const u8, offset: u64, size: u64) anyerror!objc.MTLBuffer {
+                const self_ptr: *Self = @ptrCast(@alignCast(ptr));
+                return self_ptr.getOrCreateTensorBuffer(name, offset, size);
+            }
+        }.f,
+        .isHybridMode = struct {
+            fn f(ptr: *anyopaque) bool {
+                const self_ptr: *Self = @ptrCast(@alignCast(ptr));
+                return self_ptr.hybrid_mixed_mode and self_ptr.hasHybridQ2KSource();
+            }
+        }.f,
+    };
 };

